def infix_to_postfix(infix_expression):
    precedence = {'+': 1, '-': 1, '*': 2, '/': 2, '^': 3}
    associativity = {'+': 'left', '-': 'left', '*': 'left', '/': 'left', '^': 'right'}

    operator_stack = []
    postfix_output = []

    # Simple tokenization: splits by spaces.
    # For more complex expressions (e.g., "2+3*4"), a more robust tokenizer
    # would be needed to separate operators and operands correctly.
    tokens = infix_expression.split()

    for token in tokens:
        if token.isalnum():  # Operands (numbers or variables)
            postfix_output.append(token)
        elif token == '(':
            operator_stack.append(token)
        elif token == ')':
            while operator_stack and operator_stack[-1] != '(':
                postfix_output.append(operator_stack.pop())
            if operator_stack and operator_stack[-1] == '(':
                operator_stack.pop()  # Pop the '('
            else:
                raise ValueError("Mismatched parentheses: No matching '(' found.")
        elif token in precedence:  # Operator
            while (operator_stack and operator_stack[-1] != '(' and
                   (precedence[token] < precedence[operator_stack[-1]] or
                   (precedence[token] == precedence[operator_stack[-1]] and 
                    associativity[token] == 'left'))):
                postfix_output.append(operator_stack.pop())
            operator_stack.append(token)
        else:
            raise ValueError(f"Invalid token encountered: {token}")

    while operator_stack:
        op = operator_stack.pop()
        if op == '(':
            raise ValueError("Mismatched parentheses: Unclosed '(' found.")
        postfix_output.append(op)

    return " ".join(postfix_output)

